const SE_COVER_ID_SET = new Set<string>(SE_COVER_BOOK_IDS)

/**
 * Public Storage URL for a book's text-free SE cover painting, or undefined if
 * the book has no backfilled cover yet.
 */
export function getSeCoverPath(bookId: string): string | undefined {
  if (!SE_COVER_ID_SET.has(bookId)) return undefined
  return `${SUPABASE_COVERS_BASE}/${bookId}.jpg`
}
